#!/usr/bin/env python3
import base64, os, subprocess

b64_collect = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/collect.js"), exist_ok=True)
open("/var/www/konverta/src/routes/collect.js", "wb").write(base64.b64decode(b64_collect))
print("✓ /var/www/konverta/src/routes/collect.js")

print("\n✅ country hash corrigido!")
subprocess.run(["pm2", "restart", "konverta"])